module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const labels = sections.map((s) => (s || '').trim()).filter(Boolean).slice(0, 3);
const n = labels.length >= 3 ? 3 : 2;
const palette = [args.color || 'var(--accent-color)', args.color2 || '#ef4444', args.color3 || '#22c55e'];
const opRaw = parseFloat(args.opacity);
const opacity = Number.isFinite(opRaw) ? Math.max(0, Math.min(1, opRaw)) : 0.45;
const maxW = (args.maxwidth || '400px').trim() || '400px';
// Circle centres (as % of the square box); two- and three-set arrangements.
const pos = n === 3
  ? [{ x: 38, y: 36 }, { x: 62, y: 36 }, { x: 50, y: 64 }]
  : [{ x: 38, y: 50 }, { x: 62, y: 50 }];
const lab = n === 3
  ? [{ x: 26, y: 24 }, { x: 74, y: 24 }, { x: 50, y: 82 }]
  : [{ x: 24, y: 50 }, { x: 76, y: 50 }];
let circles = '', texts = '';
for (let i = 0; i < n; i++) {
  circles += `<div class="mdp-venn-circle" style="left:${pos[i].x}%; top:${pos[i].y}%; background:${palette[i]};"></div>`;
  texts += `<div class="mdp-venn-label" style="left:${lab[i].x}%; top:${lab[i].y}%;">${esc(labels[i] || '')}</div>`;
}
const center = (args.center || '').trim() ? `<div class="mdp-venn-center">${esc(args.center.trim())}</div>` : '';
return `\n\n<div class="mdp-mod-venn mdp-venn-${n}" style="--venn-op:${opacity}; --venn-mw:${maxW};">${circles}${center}${texts}</div>\n\n`;
